using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");
            entity.HasIndex(p => p.Sku);

            // EF Core 9 breaking change #1: discriminator property renamed from
            // "Discriminator" to "$type". Existing 500K documents use "Discriminator",
            // and our raw SQL queries reference c.Discriminator — keep the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 breaking change #2: id values no longer include the
            // discriminator prefix. Old format: "Product|123", new default: "123".
            // Existing documents use the prefixed format — preserve it.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonPropertyName("id")
                  .HasValueGenerator<PrefixedIdValueGenerator>();
        });
    }
}

// Reproduces the EF Core 8 "EntityType|Key" id format so existing documents are found.
class PrefixedIdValueGenerator : Microsoft.EntityFrameworkCore.ValueGeneration.ValueGenerator<int>
{
    public override bool GeneratesTemporaryValues => false;
    public override int Next(Microsoft.EntityFrameworkCore.ChangeTracking.EntityEntry entry) =>
        throw new NotSupportedException("Use the async path or assign Id explicitly.");
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

