class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe because we preserved "Discriminator" as the
        // discriminator property name in OnModelCreating (EF 9 default is "$type").
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 breaking change #3: synchronous I/O APIs (ToList, First, Single,
        // SaveChanges, etc.) are removed for the Cosmos provider. Use async equivalents.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

