    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        // Placeholder — replace with your actual connection string and database name.
        options.UseCosmos("AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
                          "ProductsDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");
            entity.HasIndex(p => p.Sku);

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 writes "$type" by default; existing documents use "Discriminator".
